import { SkillsAgentScreen } from "@/components/skills-agent/skills-agent-screen";

export default function SkillsAgentPage() {
  return <SkillsAgentScreen />;
}

import { handleSkillsAgentRequest } from "@/lib/skills-agent/server/request";

export const runtime = "nodejs";

export function POST(request: Request) {
  return handleSkillsAgentRequest(request);
}

import { Badge } from "@/components/ui/badge";

import { getSkillsAgentRuntimeState } from "@/lib/skills-agent/server/runtime";
import { SkillsAgentWorkspace } from "./skills-agent-workspace";

export async function SkillsAgentScreen() {
  const runtimeState = await getSkillsAgentRuntimeState();

  return (
    <main className="min-h-svh bg-background text-foreground">
      <div className="mx-auto flex w-full max-w-7xl flex-col gap-6 px-4 py-6 md:px-6">
        <header className="grid gap-4 border border-foreground/10 bg-background px-4 py-5 md:grid-cols-[minmax(0,1fr)_auto] md:items-end">
          <div className="space-y-2">
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Demo / Skills Builder Agent
            </p>
            <h1 className="max-w-3xl font-medium text-2xl tracking-tight">
              Load repo-local skills on demand and turn rough ideas into durable
              agent assets
            </h1>
            <p className="max-w-3xl text-muted-foreground text-sm/relaxed">
              This workspace tracks the AI SDK skills guide closely: the model
              sees a lightweight catalog first, loads full skill instructions
              only when needed, and executes inside Vercel Sandbox.
            </p>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            <Badge variant="outline">{runtimeState.statusLabel}</Badge>
            <Badge variant="outline">{runtimeState.chatModel}</Badge>
          </div>
        </header>

        <SkillsAgentWorkspace
          availableSkills={runtimeState.availableSkills}
          chatModel={runtimeState.chatModel}
          isChatAvailable={runtimeState.isChatAvailable}
          nodeVersion={runtimeState.nodeVersion}
          sandboxProvider={runtimeState.sandboxProvider}
          setupMessage={runtimeState.setupMessage}
        />
      </div>
    </main>
  );
}

"use client";

import {
  ArrowClockwiseIcon,
  HammerIcon,
  StopIcon,
  WrenchIcon,
} from "@phosphor-icons/react";
import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import {
  Reasoning,
  ReasoningContent,
  ReasoningTrigger,
} from "@/components/ai-elements/reasoning";
import { Shimmer } from "@/components/ai-elements/shimmer";
import {
  Tool,
  ToolContent,
  ToolHeader,
  ToolInput,
  ToolOutput,
  type ToolPart,
} from "@/components/ai-elements/tool";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { isReasoningUIPart, isToolUIPart, type UIMessage } from "ai";
import { useMemo } from "react";
import { useSkillsAgentChat } from "./use-skills-agent-chat";

const configuredTools = [
  {
    description: "Load full skill instructions from the configured skills set.",
    name: "skill",
  },
  {
    description: "Run shell commands inside the session sandbox.",
    name: "bash",
  },
  {
    description: "Read sandbox-backed files directly.",
    name: "readFile",
  },
  {
    description: "Write sandbox-backed files directly.",
    name: "writeFile",
  },
] as const;

function getTextContent(message: UIMessage) {
  return message.parts
    .filter((part) => part.type === "text")
    .map((part) => part.text)
    .join("\n");
}

function getReasoningText(message: UIMessage) {
  return message.parts
    .filter(isReasoningUIPart)
    .map((part) => part.text)
    .join("\n\n");
}

function getToolParts(message: UIMessage) {
  return message.parts.filter(isToolUIPart);
}

function getToolName(part: ToolPart) {
  return part.type === "dynamic-tool"
    ? part.toolName
    : part.type.split("-").slice(1).join("-");
}

function readObjectField(value: unknown, field: string): string | null {
  if (!value || typeof value !== "object" || !(field in value)) {
    return null;
  }

  const candidate = value[field as keyof typeof value];

  return typeof candidate === "string" ? candidate : null;
}

function getActivatedSkills(toolParts: ToolPart[]) {
  return toolParts
    .filter(
      (part) =>
        getToolName(part) === "skill" && part.state === "output-available"
    )
    .map((part) => {
      const nestedSkill =
        part.output && typeof part.output === "object" && "skill" in part.output
          ? part.output.skill
          : null;

      return (
        readObjectField(nestedSkill, "name") ??
        readObjectField(part.output, "skillName")
      );
    })
    .filter((name): name is string => Boolean(name));
}

function getDraftArtifacts(toolParts: ToolPart[]) {
  return toolParts
    .filter(
      (part) =>
        getToolName(part) === "writeFile" && part.state === "output-available"
    )
    .map((part) => {
      const inputPath = readObjectField(part.input, "path");
      const inputContent = readObjectField(part.input, "content");
      const outputPath = readObjectField(part.output, "path");

      return {
        content: inputContent,
        path: outputPath ?? inputPath,
      };
    })
    .filter((artifact) => artifact.path && artifact.content);
}

interface AssistantTraceProps {
  isLastMessage: boolean;
  isStreaming: boolean;
  message: UIMessage;
}

function AssistantTrace({
  isLastMessage,
  isStreaming,
  message,
}: AssistantTraceProps) {
  const text = getTextContent(message);
  const reasoningText = getReasoningText(message);
  const toolParts = getToolParts(message);
  const activatedSkills = getActivatedSkills(toolParts);
  const draftArtifacts = getDraftArtifacts(toolParts);
  const hasReasoning = reasoningText.length > 0;
  const hasText = text.length > 0;
  const lastPart = message.parts.at(-1);
  const isReasoningStreaming =
    isLastMessage && isStreaming && lastPart?.type === "reasoning";
  const showBodyThinking =
    isLastMessage && isStreaming && !hasReasoning && !hasText;
  let bodyContent: React.ReactNode = null;

  if (hasText) {
    bodyContent = <MessageResponse>{text}</MessageResponse>;
  } else if (showBodyThinking) {
    bodyContent = <Shimmer className="text-sm">Thinking...</Shimmer>;
  }

  return (
    <>
      {hasReasoning ? (
        <Reasoning className="w-full" isStreaming={isReasoningStreaming}>
          <ReasoningTrigger />
          <ReasoningContent>{reasoningText}</ReasoningContent>
        </Reasoning>
      ) : null}

      {activatedSkills.length > 0 ? (
        <div className="space-y-2">
          <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
            Activated skills
          </p>
          <div className="flex flex-wrap gap-2">
            {activatedSkills.map((skillName) => (
              <Badge key={skillName} variant="secondary">
                {skillName}
              </Badge>
            ))}
          </div>
        </div>
      ) : null}

      {draftArtifacts.length > 0 ? (
        <div className="space-y-3">
          {draftArtifacts.map((artifact) => (
            <div
              className="space-y-2 border border-foreground/10 p-3"
              key={`${artifact.path}-${artifact.content?.length ?? 0}`}
            >
              <div className="flex items-center justify-between gap-3">
                <p className="font-medium text-sm">Draft artifact</p>
                <Badge variant="outline">{artifact.path}</Badge>
              </div>
              <pre className="overflow-x-auto whitespace-pre-wrap text-xs/relaxed">
                {artifact.content}
              </pre>
            </div>
          ))}
        </div>
      ) : null}

      {toolParts.map((part) => (
        <Tool key={part.toolCallId}>
          {part.type === "dynamic-tool" ? (
            <ToolHeader
              state={part.state}
              toolName={part.toolName}
              type={part.type}
            />
          ) : (
            <ToolHeader state={part.state} type={part.type} />
          )}
          <ToolContent>
            {part.input ? <ToolInput input={part.input} /> : null}
            <ToolOutput errorText={part.errorText} output={part.output} />
          </ToolContent>
        </Tool>
      ))}

      {bodyContent}
    </>
  );
}

export interface SkillsAgentWorkspaceProps {
  availableSkills: Array<{
    description: string;
    name: string;
  }>;
  chatModel: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  sandboxProvider: string;
  setupMessage: string | null;
}

export function SkillsAgentWorkspace({
  availableSkills,
  chatModel,
  isChatAvailable,
  nodeVersion,
  sandboxProvider,
  setupMessage,
}: SkillsAgentWorkspaceProps) {
  const {
    error,
    hasMessages,
    isBusy,
    messages,
    regenerate,
    sendMessage,
    status,
    stop,
  } = useSkillsAgentChat();
  const samplePrompts = useMemo(
    () => [
      "Grill this rough idea for a docs chatbot.",
      "Interrogate this agent concept until the glossary and boundaries are precise.",
      "After the context is aligned, draft a reusable SKILL.md package for the workflow.",
    ],
    []
  );

  return (
    <div className="grid min-h-[70svh] gap-4 lg:grid-cols-[minmax(0,1fr)_22rem]">
      <section className="flex min-h-[70svh] flex-col border border-foreground/10 bg-background">
        {isChatAvailable ? null : (
          <div className="border-foreground/10 border-b px-4 py-3 text-muted-foreground text-xs/relaxed">
            {setupMessage}
          </div>
        )}

        {error ? (
          <div className="border-foreground/10 border-b px-4 py-3 text-destructive text-xs/relaxed">
            {error.message}
          </div>
        ) : null}

        <Conversation>
          <ConversationContent className="mx-auto flex w-full max-w-3xl flex-1 gap-6 px-4 py-6">
            {hasMessages ? (
              messages.map((message, index) => (
                <Message from={message.role} key={message.id}>
                  <MessageContent
                    className={cn(
                      "space-y-4",
                      message.role === "assistant" ? "max-w-3xl" : "max-w-2xl"
                    )}
                  >
                    {message.role === "assistant" ? (
                      <AssistantTrace
                        isLastMessage={index === messages.length - 1}
                        isStreaming={isBusy}
                        message={message}
                      />
                    ) : (
                      <MessageResponse>
                        {getTextContent(message)}
                      </MessageResponse>
                    )}
                  </MessageContent>
                </Message>
              ))
            ) : (
              <ConversationEmptyState
                description="Ask the agent to challenge a rough idea, align durable context, and turn that workflow into a reusable skill draft."
                icon={<HammerIcon className="size-5" />}
                title="Idea-to-skill workspace is ready"
              />
            )}
          </ConversationContent>
          <ConversationScrollButton />
        </Conversation>

        <div className="border-foreground/10 border-t px-4 py-4">
          <div className="mx-auto w-full max-w-3xl">
            <PromptInput onSubmit={({ text }) => sendMessage({ text })}>
              <PromptInputBody>
                <PromptInputTextarea
                  disabled={!isChatAvailable || isBusy}
                  placeholder="Describe a rough idea or ask for a reusable skill draft."
                />
              </PromptInputBody>
              <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant="outline">ToolLoopAgent</Badge>
                  <Badge variant="outline">Vercel Sandbox</Badge>
                  <Badge variant="outline">{chatModel}</Badge>
                </div>
                <div className="flex items-center gap-2">
                  {isBusy ? (
                    <Button
                      onClick={stop}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <StopIcon className="size-3.5" />
                      Stop
                    </Button>
                  ) : null}
                  {hasMessages ? (
                    <Button
                      onClick={() => regenerate()}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <ArrowClockwiseIcon className="size-3.5" />
                      Retry
                    </Button>
                  ) : null}
                  <PromptInputSubmit
                    disabled={!isChatAvailable}
                    status={status}
                  />
                </div>
              </PromptInputFooter>
            </PromptInput>

            {hasMessages ? null : (
              <div className="mt-3 flex flex-wrap gap-2">
                {samplePrompts.map((prompt) => (
                  <Button
                    key={prompt}
                    onClick={() => sendMessage({ text: prompt })}
                    size="sm"
                    type="button"
                    variant="outline"
                  >
                    <WrenchIcon className="size-3.5" />
                    {prompt}
                  </Button>
                ))}
              </div>
            )}
          </div>
        </div>
      </section>

      <aside className="border border-foreground/10 bg-background p-4">
        <div className="space-y-5">
          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Runtime
            </p>
            <p className="mt-1 font-medium text-sm">{nodeVersion}</p>
            <p className="mt-1 text-muted-foreground text-sm">
              {sandboxProvider}
            </p>
          </div>

          <div className="space-y-2">
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Available skills
            </p>
            {availableSkills.map((skill) => (
              <div
                className="space-y-1 border border-foreground/10 p-3"
                key={skill.name}
              >
                <p className="font-medium text-sm">{skill.name}</p>
                <p className="text-muted-foreground text-sm/relaxed">
                  {skill.description}
                </p>
              </div>
            ))}
          </div>

          <div className="space-y-2">
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Configured tools
            </p>
            {configuredTools.map((tool) => (
              <div
                className="space-y-1 border border-foreground/10 p-3"
                key={tool.name}
              >
                <p className="font-medium text-sm">{tool.name}</p>
                <p className="text-muted-foreground text-sm/relaxed">
                  {tool.description}
                </p>
              </div>
            ))}
          </div>

          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Artifact targets
            </p>
            <div className="mt-2 flex flex-wrap gap-2">
              <Badge variant="secondary">artifacts/CONTEXT.md</Badge>
              <Badge variant="secondary">
                artifacts/&lt;skill&gt;/SKILL.md
              </Badge>
            </div>
          </div>

          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Source core
            </p>
            <p className="mt-1 text-sm">
              The model starts from skill metadata, calls <code>skill</code> for
              full instructions, then uses sandbox tools for file and shell
              work.
            </p>
          </div>
        </div>
      </aside>
    </div>
  );
}

"use client";

import { Chat, useChat } from "@ai-sdk/react";
import { DefaultChatTransport } from "ai";
import { useState } from "react";

export function useSkillsAgentChat() {
  const [chat] = useState(
    () =>
      new Chat({
        transport: new DefaultChatTransport({
          api: "/api/demos/skills-agent",
        }),
      })
  );
  const controller = useChat({ chat });
  const hasMessages = controller.messages.length > 0;
  const isBusy =
    controller.status === "submitted" || controller.status === "streaming";

  return {
    ...controller,
    chat,
    hasMessages,
    isBusy,
  };
}

"use client";

import { CornerDownLeftIcon, LoaderCircleIcon, SquareIcon } from "lucide-react";
import type {
  ComponentProps,
  FormEvent,
  HTMLAttributes,
  ReactNode,
  TextareaHTMLAttributes,
} from "react";
import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

type PromptStatus = "error" | "ready" | "streaming" | "submitted";

interface PromptInputContextValue {
  setText: (text: string) => void;
  text: string;
}

interface PromptInputMessage {
  text: string;
}

interface PromptInputProps
  extends Omit<HTMLAttributes<HTMLFormElement>, "onSubmit"> {
  children: ReactNode;
  onSubmit: (
    message: PromptInputMessage,
    event: FormEvent<HTMLFormElement>
  ) => void | Promise<void>;
}

interface PromptInputSubmitProps
  extends Omit<ComponentProps<typeof Button>, "children" | "type"> {
  onStop?: () => void;
  status?: PromptStatus;
}

type PromptInputClickEvent = Parameters<
  Exclude<ComponentProps<typeof Button>["onClick"], undefined>
>[0];

const PromptInputContext = createContext<PromptInputContextValue | null>(null);

function usePromptInputContext() {
  const context = useContext(PromptInputContext);

  if (!context) {
    throw new Error(
      "PromptInput components must be used inside <PromptInput>."
    );
  }

  return context;
}

export function PromptInput({
  children,
  className,
  onSubmit,
  ...props
}: PromptInputProps) {
  const [text, setText] = useState("");

  const contextValue = useMemo(
    () => ({
      setText,
      text,
    }),
    [text]
  );

  const handleSubmit = useCallback(
    async (event: FormEvent<HTMLFormElement>) => {
      event.preventDefault();

      const nextText = text.trim();
      if (!nextText) {
        return;
      }

      const result = onSubmit({ text: nextText }, event);

      try {
        await result;
        setText("");
      } catch {
        // Keep the text for retry after a failed submit.
      }
    },
    [onSubmit, text]
  );

  return (
    <PromptInputContext.Provider value={contextValue}>
      <form
        className={cn("w-full", className)}
        onSubmit={handleSubmit}
        {...props}
      >
        {children}
      </form>
    </PromptInputContext.Provider>
  );
}

export function PromptInputBody({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn("grid gap-3", className)} {...props} />;
}

export function PromptInputFooter({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn(className)} {...props} />;
}

export function PromptInputTextarea({
  className,
  disabled,
  onChange,
  ...props
}: TextareaHTMLAttributes<HTMLTextAreaElement>) {
  const context = usePromptInputContext();

  return (
    <Textarea
      className={cn("min-h-16 resize-none", className)}
      disabled={disabled}
      onChange={(event) => {
        context.setText(event.currentTarget.value);
        onChange?.(event);
      }}
      value={context.text}
      {...props}
    />
  );
}

export function PromptInputSubmit({
  className,
  disabled,
  onClick,
  onStop,
  size = "icon",
  status = "ready",
  variant = "default",
  ...props
}: PromptInputSubmitProps) {
  const { text } = usePromptInputContext();
  const isBusy = status === "submitted" || status === "streaming";
  const isDisabled = Boolean(disabled) || (!isBusy && text.trim().length === 0);

  let icon = <CornerDownLeftIcon className="size-4" />;

  if (status === "submitted") {
    icon = <LoaderCircleIcon className="size-4 animate-spin" />;
  } else if (status === "streaming") {
    icon = <SquareIcon className="size-4" />;
  }

  return (
    <Button
      aria-label={isBusy ? "Stop" : "Submit"}
      className={cn(className)}
      disabled={isDisabled}
      onClick={(event: PromptInputClickEvent) => {
        if (isBusy && onStop) {
          event.preventDefault();
          onStop();
          return;
        }

        onClick?.(event);
      }}
      size={size}
      type={isBusy && onStop ? "button" : "submit"}
      variant={variant}
      {...props}
    >
      {icon}
    </Button>
  );
}

import {
  createAgentUIStreamResponse,
  stepCountIs,
  ToolLoopAgent,
  type UIMessage,
} from "ai";
import { z } from "zod";
import { createSkillsAgentGateway, getSkillsAgentEnv } from "./env";
import {
  resolveSkillsAgentChatModel,
  SKILLS_AGENT_PROVIDER_OPTIONS,
} from "./model";
import type { SkillMetadata } from "./skill-catalog";
import { createSkillsAgentWorkspace } from "./workspace";

type DemoEnv = Record<string, string | undefined>;

const skillOptionSchema = z.object({
  description: z.string(),
  name: z.string(),
  path: z.string(),
});

const skillsAgentCallOptionsSchema = z.object({
  skills: z.array(skillOptionSchema).min(1),
});

type SkillsAgentCallOptions = z.infer<typeof skillsAgentCallOptionsSchema>;

export const skillsAgentInstructions = [
  "You are the skills-agent demo for a product and engineering team.",
  "Treat the visible skill catalog as lightweight metadata. Load the full SKILL.md only when you decide a skill is needed.",
  "Choose a skill based on the visible catalog descriptions when the user's request matches one of them.",
  "Use readFile, writeFile, and bash inside the Vercel Sandbox when the skill instructions require repository context or generated artifacts.",
  "Follow the loaded skill's filesystem conventions. grill-with-docs owns repository paths like CONTEXT.md and docs/adr/, while artifacts/ is for standalone drafts when a skill does not specify a canonical location.",
  "Repository files such as CONTEXT.md or docs/adr/ may not exist yet. Use bash checks like test -f or ls before reading optional files, and create them lazily when the loaded skill calls for that.",
  "Keep the final answer concise and report any artifact paths that were created or updated.",
].join(" ");

export async function streamSkillsAgent(
  messages: UIMessage[],
  {
    env = getSkillsAgentEnv(),
    sessionId,
    skills,
  }: {
    env?: DemoEnv;
    sessionId: string;
    skills: SkillMetadata[];
  }
) {
  const gateway = createSkillsAgentGateway(env);
  const chatModel = resolveSkillsAgentChatModel(env);
  const workspace = await createSkillsAgentWorkspace({
    env,
    sessionId,
    skills,
  });

  const agent = new ToolLoopAgent<SkillsAgentCallOptions>({
    instructions: skillsAgentInstructions,
    model: gateway(chatModel),
    prepareCall: ({ options, ...call }) => ({
      ...call,
      instructions: [
        skillsAgentInstructions,
        `Visible skill catalog:\n${workspace.visibleSkillCatalogText}`,
        `Sandbox project root: ${workspace.projectRoot}`,
        `Default artifacts root: ${workspace.artifactsRoot}`,
      ].join("\n\n"),
    }),
    providerOptions: SKILLS_AGENT_PROVIDER_OPTIONS,
    callOptionsSchema: skillsAgentCallOptionsSchema,
    stopWhen: stepCountIs(8),
    tools: workspace.toolset.tools,
  });

  return await createAgentUIStreamResponse({
    agent,
    options: {
      skills: workspace.visibleSkillCatalog,
    },
    sendReasoning: true,
    uiMessages: messages,
  });
}

import { createGateway } from "ai";
const DEFAULT_GATEWAY_BASE_URL = "https://ai-gateway.vercel.sh/v3/ai";
export const DEFAULT_SKILLS_AGENT_CHAT_MODEL = "openai/gpt-5-mini";
const MINIMUM_NODE_VERSION = "22.13.0";
const nodeVersionPattern = /^v?(\d+)\.(\d+)\.(\d+)(?:[-+].*)?$/;

interface ParsedNodeVersion {
  major: number;
  minor: number;
  patch: number;
}

export type SkillsAgentEnv = Record<string, string | undefined>;

export interface SkillsAgentConfig {
  apiKey: string;
  baseURL: string;
  chatModel: string;
}

export interface SkillsAgentSandboxTokenCredentials {
  projectId: string;
  teamId: string;
  token: string;
}

export interface SkillsAgentSandboxSetupState {
  authMode: "missing" | "oidc" | "token";
  isReady: boolean;
  issues: string[];
  providerLabel: "Vercel Sandbox";
  runtime: "node24";
}

export interface SkillsAgentSetupState {
  config: Omit<SkillsAgentConfig, "apiKey">;
  isReady: boolean;
  issues: string[];
  nodeVersion: string;
  sandboxProvider: SkillsAgentSandboxSetupState["providerLabel"];
}

function parseNodeVersion(version: string): ParsedNodeVersion {
  const match = nodeVersionPattern.exec(version);
  const major = Number(match?.[1]);
  const minor = Number(match?.[2]);
  const patch = Number(match?.[3]);

  if (![major, minor, patch].every(Number.isInteger)) {
    throw new Error(`Unable to parse Node.js version: "${version}".`);
  }

  return { major, minor, patch };
}

function compareNodeVersions(
  left: ParsedNodeVersion,
  right: ParsedNodeVersion
) {
  if (left.major !== right.major) {
    return left.major - right.major;
  }

  if (left.minor !== right.minor) {
    return left.minor - right.minor;
  }

  return left.patch - right.patch;
}

function assertSupportedNodeRuntime(version = process.version) {
  const parsedVersion = parseNodeVersion(version);
  const minimumVersion = parseNodeVersion(MINIMUM_NODE_VERSION);

  if (compareNodeVersions(parsedVersion, minimumVersion) < 0) {
    throw new Error(
      `Node.js ${version} is unsupported. This demo workspace requires Node.js >=${MINIMUM_NODE_VERSION}.`
    );
  }
}

export function getSkillsAgentEnv(): SkillsAgentEnv {
  // biome-ignore lint/style/noProcessEnv: Registry source installs into consumer apps without this repo's env wrapper.
  return process.env;
}

function readRequiredEnv(env: SkillsAgentEnv, name: keyof SkillsAgentEnv) {
  const value = env[name];

  if (!value) {
    throw new Error(
      `Missing ${name}. Add it to .env.local before using the skills agent.`
    );
  }

  return value;
}

function resolveSkillsAgentEnv(env: SkillsAgentEnv = getSkillsAgentEnv()) {
  return {
    apiKey: env.AI_GATEWAY_API_KEY,
    baseURL: env.AI_GATEWAY_BASE_URL || DEFAULT_GATEWAY_BASE_URL,
    chatModel: env.AI_GATEWAY_CHAT_MODEL || DEFAULT_SKILLS_AGENT_CHAT_MODEL,
  };
}

export function getSkillsAgentConfig(
  env: SkillsAgentEnv = getSkillsAgentEnv()
): SkillsAgentConfig {
  assertSupportedNodeRuntime();
  const resolvedEnv = resolveSkillsAgentEnv(env);

  return {
    apiKey: readRequiredEnv(env, "AI_GATEWAY_API_KEY"),
    baseURL: resolvedEnv.baseURL,
    chatModel: resolvedEnv.chatModel,
  };
}

export function hasSkillsAgentSandboxTokenCredentials(env: SkillsAgentEnv) {
  return Boolean(
    env.VERCEL_PROJECT_ID && env.VERCEL_TEAM_ID && env.VERCEL_TOKEN
  );
}

export function getSkillsAgentSandboxTokenCredentials(
  env: SkillsAgentEnv = getSkillsAgentEnv()
): SkillsAgentSandboxTokenCredentials {
  const { VERCEL_PROJECT_ID, VERCEL_TEAM_ID, VERCEL_TOKEN } = env;

  if (!(VERCEL_PROJECT_ID && VERCEL_TEAM_ID && VERCEL_TOKEN)) {
    throw new Error(
      "Vercel Sandbox token credentials are incomplete. Expected VERCEL_TOKEN, VERCEL_TEAM_ID, and VERCEL_PROJECT_ID."
    );
  }

  return {
    projectId: VERCEL_PROJECT_ID,
    teamId: VERCEL_TEAM_ID,
    token: VERCEL_TOKEN,
  };
}

export function getSkillsAgentSandboxSetupState(
  env: SkillsAgentEnv = getSkillsAgentEnv()
): SkillsAgentSandboxSetupState {
  const issues: string[] = [];
  const hasOidc = Boolean(env.VERCEL_OIDC_TOKEN);
  let authMode: SkillsAgentSandboxSetupState["authMode"] = "missing";

  if (hasOidc) {
    authMode = "oidc";
  } else if (hasSkillsAgentSandboxTokenCredentials(env)) {
    authMode = "token";
  }

  if (authMode === "missing") {
    issues.push(
      "Vercel Sandbox credentials are missing. Add VERCEL_OIDC_TOKEN or the VERCEL_TOKEN, VERCEL_TEAM_ID, and VERCEL_PROJECT_ID trio."
    );
  }

  return {
    authMode,
    isReady: issues.length === 0,
    issues,
    providerLabel: "Vercel Sandbox",
    runtime: "node24",
  };
}

export function getSkillsAgentSetupState(
  env: SkillsAgentEnv = getSkillsAgentEnv()
): SkillsAgentSetupState {
  const issues: string[] = [];
  const resolvedEnv = resolveSkillsAgentEnv(env);
  const sandboxSetup = getSkillsAgentSandboxSetupState(env);

  try {
    assertSupportedNodeRuntime();
  } catch (error) {
    issues.push(
      error instanceof Error ? error.message : "Unsupported Node.js runtime."
    );
  }

  if (!resolvedEnv.apiKey) {
    issues.push(
      "AI_GATEWAY_API_KEY is missing. The demo can render, but skills-agent chat requests will fail until it is configured."
    );
  }

  issues.push(...sandboxSetup.issues);

  return {
    config: {
      baseURL: resolvedEnv.baseURL,
      chatModel: resolvedEnv.chatModel,
    },
    isReady: issues.length === 0,
    issues,
    nodeVersion: process.version,
    sandboxProvider: sandboxSetup.providerLabel,
  };
}

export function createSkillsAgentGateway(
  env: SkillsAgentEnv = getSkillsAgentEnv()
) {
  const { apiKey, baseURL } = getSkillsAgentConfig(env);

  return createGateway({
    apiKey,
    baseURL,
  });
}

