export interface SkillsAgentRuntimeState {
  availableSkills: Pick<SkillMetadata, "description" | "name">[];
  chatModel: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  sandboxProvider: string;
  setupMessage: string | null;
  statusLabel: "Ready" | "Setup required";
}

export async function getSkillsAgentRuntimeState(
  env: DemoEnv = getSkillsAgentEnv(),
  dependencies: {
    discoverSkills: () => Promise<SkillMetadata[]>;
  } = {
    discoverSkills: discoverWorkspaceSkills,
  }
): Promise<SkillsAgentRuntimeState> {
  const setup = getSkillsAgentSetupState(env);
  const skills = await dependencies.discoverSkills();
  const issues = [...setup.issues];

  if (skills.length === 0) {
    issues.push(
      'No primary skills were found under ".agents/skills". The demo expects grill-with-docs and skill-creator.'
    );
  }

  return {
    availableSkills: skills.map(({ description, name }) => ({
      description,
      name,
    })),
    chatModel: setup.config.chatModel,
    isChatAvailable: issues.length === 0,
    nodeVersion: setup.nodeVersion,
    sandboxProvider: setup.sandboxProvider,
    setupMessage: issues.length > 0 ? issues.join(" ") : null,
    statusLabel: issues.length === 0 ? "Ready" : "Setup required",
  };
}

import { type UIMessage, validateUIMessages } from "ai";

import { getSkillsAgentEnv } from "./env";
import { discoverWorkspaceSkills } from "./local-skill-catalog";
import { getSkillsAgentRuntimeState } from "./runtime";
import type { SkillMetadata } from "./skill-catalog";

type DemoEnv = Record<string, string | undefined>;

interface SkillsAgentRequestBody {
  id?: string;
  messages?: UIMessage[];
}

interface StreamSkillsAgentOptions {
  sessionId: string;
  skills: SkillMetadata[];
}

interface SkillsAgentRequestDependencies {
  discoverSkills: () => Promise<SkillMetadata[]>;
  streamSkillsAgent: (
    messages: UIMessage[],
    options: StreamSkillsAgentOptions
  ) => Promise<Response> | Response;
}

const invalidUiMessagesError =
  'Expected each "messages" entry to match the UIMessage format.';
const invalidChatIdError =
  'Expected a JSON body with an "id" string and a "messages" array.';

async function readSkillsAgentRequest(
  body: unknown
): Promise<{ messages: UIMessage[]; sessionId: string }> {
  const { id, messages } = (body ?? {}) as SkillsAgentRequestBody;

  if (!(typeof id === "string" && id.length > 0 && Array.isArray(messages))) {
    throw new Error(invalidChatIdError);
  }

  try {
    return {
      messages: await validateUIMessages({ messages }),
      sessionId: id,
    };
  } catch {
    throw new Error(invalidUiMessagesError);
  }
}

export async function handleSkillsAgentRequest(
  request: Request,
  env: DemoEnv = getSkillsAgentEnv(),
  dependencies: Partial<SkillsAgentRequestDependencies> = {
    discoverSkills: discoverWorkspaceSkills,
    streamSkillsAgent: async (messages, options) => {
      const { streamSkillsAgent } = await import("./chat");

      return streamSkillsAgent(messages, {
        env,
        sessionId: options.sessionId,
        skills: options.skills,
      });
    },
  }
) {
  const discoverSkills = dependencies.discoverSkills ?? discoverWorkspaceSkills;
  const streamAgent =
    dependencies.streamSkillsAgent ??
    (async (messages: UIMessage[], options: StreamSkillsAgentOptions) => {
      const { streamSkillsAgent } = await import("./chat");

      return streamSkillsAgent(messages, {
        env,
        sessionId: options.sessionId,
        skills: options.skills,
      });
    });
  const runtimeState = await getSkillsAgentRuntimeState(env, {
    discoverSkills,
  });

  if (!runtimeState.isChatAvailable) {
    return Response.json(
      {
        error: runtimeState.setupMessage,
      },
      { status: 500 }
    );
  }

  try {
    const { messages, sessionId } = await readSkillsAgentRequest(
      await request.json()
    );
    const skills = await discoverSkills();

    return streamAgent(messages, { sessionId, skills });
  } catch (error) {
    if (
      error instanceof Error &&
      [invalidUiMessagesError, invalidChatIdError].includes(error.message)
    ) {
      return Response.json(
        {
          error: error.message,
        },
        { status: 400 }
      );
    }

    throw error;
  }
}

import path, { posix as posixPath } from "node:path";
import {
  copyLocalPathToSandbox,
  createVercelSandbox,
  createVercelSandboxSessionRegistry,
  VERCEL_SANDBOX_AGENTS_FILE,
  VERCEL_SANDBOX_ARTIFACTS_ROOT,
  VERCEL_SANDBOX_PROJECT_ROOT,
  VERCEL_SANDBOX_SKILLS_ROOT,
  type VercelSandboxFactory,
  type VercelSandboxHandle,
  type VercelSandboxSession,
  type VercelSandboxSessionRegistry,
} from "./vercel-sandbox";
import {
  getSkillsAgentEnv,
  getSkillsAgentSandboxSetupState as getSkillsAgentSandboxSetup,
  type SkillsAgentEnv,
  type SkillsAgentSandboxSetupState,
} from "./env";
import { SKILLS_AGENT_WORKSPACE_ROOT } from "./local-skill-catalog";
import {
  type LoadedSkill,
  loadSkill,
  type SkillMetadata,
} from "./skill-catalog";

export type SkillsAgentSandboxHandle = VercelSandboxHandle;
export type SandboxFactory = VercelSandboxFactory;
export const SANDBOX_PROJECT_ROOT = VERCEL_SANDBOX_PROJECT_ROOT;
export const SANDBOX_SKILLS_ROOT = VERCEL_SANDBOX_SKILLS_ROOT;
export const SANDBOX_ARTIFACTS_ROOT = VERCEL_SANDBOX_ARTIFACTS_ROOT;
export const SANDBOX_AGENTS_FILE = VERCEL_SANDBOX_AGENTS_FILE;

export interface SkillsAgentSession extends VercelSandboxSession {
  readonly activeSkillDirectory: string | null;
  loadSkill(skills: SkillMetadata[], name: string): Promise<LoadedSkill>;
}

export interface SkillsAgentSessionRegistry {
  getSession(sessionId: string): SkillsAgentSession;
  stopSession(sessionId: string): Promise<void>;
}

interface SessionEntry {
  activeSkillDirectory: string | null;
  hydratedSkillNames: Set<string>;
}

function resolveSessionPath(entry: SessionEntry, targetPath: string) {
  if (targetPath.startsWith("/")) {
    return targetPath;
  }

  if (
    entry.activeSkillDirectory &&
    (targetPath === "." ||
      targetPath.startsWith("./") ||
      targetPath.startsWith("../"))
  ) {
    return posixPath.normalize(
      posixPath.join(entry.activeSkillDirectory, targetPath)
    );
  }

  return targetPath;
}

export const createSkillsAgentSandbox = createVercelSandbox;
export const getSkillsAgentSandboxSetupState = getSkillsAgentSandboxSetup;

export function createSkillsAgentSessionRegistry({
  createSandbox,
  workspaceRoot = SKILLS_AGENT_WORKSPACE_ROOT,
}: {
  createSandbox: SandboxFactory;
  workspaceRoot?: string;
}): SkillsAgentSessionRegistry {
  const baseRegistry: VercelSandboxSessionRegistry =
    createVercelSandboxSessionRegistry({
      createSandbox,
      workspaceRoot,
    });
  const entries = new Map<string, SessionEntry>();

  const getOrCreateEntry = (sessionId: string) => {
    const existingEntry = entries.get(sessionId);

    if (existingEntry) {
      return existingEntry;
    }

    const createdEntry: SessionEntry = {
      activeSkillDirectory: null,
      hydratedSkillNames: new Set<string>(),
    };
    entries.set(sessionId, createdEntry);
    return createdEntry;
  };

  const ensureSkillHydrated = async (
    entry: SessionEntry,
    sessionId: string,
    skill: SkillMetadata
  ) => {
    if (entry.hydratedSkillNames.has(skill.name)) {
      return;
    }

    const sandbox = await baseRegistry.getSandbox(sessionId);
    await copyLocalPathToSandbox(
      sandbox,
      skill.path,
      posixPath.join(SANDBOX_SKILLS_ROOT, path.basename(skill.path))
    );
    entry.hydratedSkillNames.add(skill.name);
  };

  return {
    getSession(sessionId) {
      const entry = getOrCreateEntry(sessionId);
      const baseSession = baseRegistry.getSession(sessionId);

      return {
        get activeSkillDirectory() {
          return entry.activeSkillDirectory;
        },
        artifactsRoot: SANDBOX_ARTIFACTS_ROOT,
        projectRoot: SANDBOX_PROJECT_ROOT,
        sessionId,
        async loadSkill(skills, name) {
          const skill = skills.find(
            (candidate) => candidate.name.toLowerCase() === name.toLowerCase()
          );

          if (!skill) {
            throw new Error(`Skill "${name}" was not found in the catalog.`);
          }

          await ensureSkillHydrated(entry, sessionId, skill);

          return loadSkill(
            {
              exec: async () => ({
                stderr: "",
                stdout: "",
              }),
              readdir: async () => [],
              readFile: (filePath, encoding) =>
                baseSession.readFile(filePath).then((content) => {
                  if (encoding !== "utf-8") {
                    throw new Error(`Unexpected encoding ${encoding}`);
                  }

                  return content;
                }),
            },
            [
              {
                ...skill,
                path: posixPath.join(
                  SANDBOX_SKILLS_ROOT,
                  path.basename(skill.path)
                ),
              },
            ],
            name
          ).then((loadedSkill) => {
            entry.activeSkillDirectory = loadedSkill.skillDirectory;
            return loadedSkill;
          });
        },
        pathExists(targetPath) {
          return baseSession.pathExists(resolveSessionPath(entry, targetPath));
        },
        readFile(targetPath) {
          return baseSession.readFile(resolveSessionPath(entry, targetPath));
        },
        runCommand(command) {
          return baseSession.runCommand(command);
        },
        stop() {
          return baseRegistry.stopSession(sessionId);
        },
        writeFile(targetPath, content) {
          return baseSession.writeFile(
            resolveSessionPath(entry, targetPath),
            content
          );
        },
      };
    },
    async stopSession(sessionId) {
      await baseRegistry.stopSession(sessionId);
      entries.delete(sessionId);
    },
  };
}

let sharedRegistry: SkillsAgentSessionRegistry | null = null;

export function getSharedSkillsAgentSessionRegistry(
  env: SkillsAgentEnv = getSkillsAgentEnv()
) {
  sharedRegistry ??= createSkillsAgentSessionRegistry({
    createSandbox: (sessionId) => createVercelSandbox(sessionId, env),
  });

  return sharedRegistry;
}

interface SkillDirent {
  isDirectory(): boolean;
  name: string;
}

export interface SkillsSandbox {
  exec(command: string): Promise<{ stderr: string; stdout: string }>;
  readdir(
    path: string,
    opts?: { withFileTypes?: boolean }
  ): Promise<SkillDirent[] | string[]>;
  readFile(path: string, encoding: BufferEncoding | "utf-8"): Promise<string>;
}

export interface SkillMetadata {
  description: string;
  name: string;
  path: string;
}

export interface LoadedSkill {
  content: string;
  name: string;
  skillDirectory: string;
}

const frontmatterPattern = /^---\r?\n([\s\S]*?)\r?\n---\r?\n?/;
const trailingSlashPattern = /\/$/;
const frontmatterDescriptionPattern = /^description:\s*(.+)$/m;
const frontmatterNamePattern = /^name:\s*(.+)$/m;

function joinPath(directory: string, name: string) {
  return `${directory.replace(trailingSlashPattern, "")}/${name}`;
}

function parseSkillMetadata(
  content: string
): Omit<SkillMetadata, "path"> | null {
  const match = content.match(frontmatterPattern);

  if (!match) {
    return null;
  }

  const frontmatter = match[1] ?? "";
  const name = frontmatter.match(frontmatterNamePattern)?.[1]?.trim();
  const description = frontmatter
    .match(frontmatterDescriptionPattern)?.[1]
    ?.trim();

  if (!(name && description)) {
    return null;
  }

  return {
    description,
    name,
  };
}

export function stripFrontmatter(content: string) {
  const match = content.match(frontmatterPattern);

  return match ? content.slice(match[0].length).trim() : content.trim();
}

export async function discoverSkills(
  sandbox: SkillsSandbox,
  directories: string[]
): Promise<SkillMetadata[]> {
  const seen = new Set<string>();
  const skills: SkillMetadata[] = [];

  for (const directory of directories) {
    const entries = (await sandbox.readdir(directory, {
      withFileTypes: true,
    })) as SkillDirent[];

    for (const entry of entries) {
      if (!entry.isDirectory()) {
        continue;
      }

      const skillDirectory = joinPath(directory, entry.name);
      const skillFile = joinPath(skillDirectory, "SKILL.md");

      try {
        const content = await sandbox.readFile(skillFile, "utf-8");
        const metadata = parseSkillMetadata(content);

        if (!metadata || seen.has(metadata.name.toLowerCase())) {
          continue;
        }

        seen.add(metadata.name.toLowerCase());
        skills.push({
          ...metadata,
          path: skillDirectory,
        });
      } catch {
        // Ignore directories without a readable SKILL.md.
      }
    }
  }

  return skills.sort((left, right) => left.name.localeCompare(right.name));
}

export async function loadSkill(
  sandbox: SkillsSandbox,
  skills: SkillMetadata[],
  name: string
): Promise<LoadedSkill> {
  const skill = skills.find(
    (candidate) => candidate.name.toLowerCase() === name.toLowerCase()
  );

  if (!skill) {
    throw new Error(`Skill "${name}" was not found in the catalog.`);
  }

  const content = await sandbox.readFile(
    joinPath(skill.path, "SKILL.md"),
    "utf-8"
  );

  return {
    content: stripFrontmatter(content),
    name: skill.name,
    skillDirectory: skill.path,
  };
}

import { existsSync } from "node:fs";
import { readdir, readFile, stat } from "node:fs/promises";
import path, { posix as posixPath } from "node:path";
import { Sandbox } from "@vercel/sandbox";
import {
  getSkillsAgentEnv,
  getSkillsAgentSandboxSetupState,
  getSkillsAgentSandboxTokenCredentials,
  type SkillsAgentEnv,
} from "./env";

function resolveVercelSandboxWorkspaceRoot() {
  const candidates = [
    process.cwd(),
    path.resolve(process.cwd(), "../.."),
  ];

  for (const candidate of candidates) {
    if (existsSync(path.join(candidate, "AGENTS.md"))) {
      return candidate;
    }
  }

  return process.cwd();
}

export const VERCEL_SANDBOX_WORKSPACE_ROOT = resolveVercelSandboxWorkspaceRoot();
export const VERCEL_SANDBOX_PROJECT_ROOT = "/vercel/sandbox/project";
export const VERCEL_SANDBOX_SKILLS_ROOT =
  `${VERCEL_SANDBOX_PROJECT_ROOT}/.agents/skills`;
export const VERCEL_SANDBOX_ARTIFACTS_ROOT =
  `${VERCEL_SANDBOX_PROJECT_ROOT}/artifacts`;
export const VERCEL_SANDBOX_AGENTS_FILE =
  `${VERCEL_SANDBOX_PROJECT_ROOT}/AGENTS.md`;

interface SandboxFs {
  exists(path: string): Promise<boolean>;
  mkdir(path: string, options?: { recursive?: boolean }): Promise<void>;
  readFile(path: string, encoding: BufferEncoding | "utf-8"): Promise<string>;
  writeFile(
    path: string,
    content: string | Uint8Array,
    encoding?: BufferEncoding | "utf-8"
  ): Promise<void>;
}

export interface VercelSandboxHandle {
  fs: SandboxFs;
  runCommand(options: { args: string[]; cmd: string; cwd: string }): Promise<{
    exitCode: number;
    stderr(): Promise<string>;
    stdout(): Promise<string>;
  }>;
  stop(): Promise<unknown>;
}

export type VercelSandboxFactory = (
  sessionId: string
) => Promise<VercelSandboxHandle>;

export interface VercelSandboxSession {
  readonly artifactsRoot: string;
  pathExists(targetPath: string): Promise<boolean>;
  readonly projectRoot: string;
  readFile(targetPath: string): Promise<string>;
  runCommand(command: string): Promise<{
    command: string;
    exitCode: number;
    stderr: string;
    stdout: string;
  }>;
  readonly sessionId: string;
  stop(): Promise<void>;
  writeFile(
    targetPath: string,
    content: string
  ): Promise<{
    bytes: number;
    path: string;
  }>;
}

export interface VercelSandboxSessionRegistry {
  getSandbox(sessionId: string): Promise<VercelSandboxHandle>;
  getSession(sessionId: string): VercelSandboxSession;
  stopSession(sessionId: string): Promise<void>;
}

interface SessionEntry {
  sandboxPromise: Promise<VercelSandboxHandle> | null;
  seededBaseWorkspace: boolean;
}

export async function createVercelSandbox(
  sessionId: string,
  env: SkillsAgentEnv = getSkillsAgentEnv(),
  options: {
    ports?: number[];
  } = {}
): Promise<VercelSandboxHandle> {
  const setupState = getSkillsAgentSandboxSetupState(env);

  if (!setupState.isReady) {
    throw new Error(setupState.issues.join(" "));
  }

  const baseOptions = {
    name: sessionId,
    persistent: true,
    ports: options.ports,
    runtime: setupState.runtime,
    timeout: 300_000,
  };

  if (setupState.authMode === "oidc") {
    try {
      return (await Sandbox.get({
        name: sessionId,
      })) as unknown as VercelSandboxHandle;
    } catch {
      return (await Sandbox.create(
        baseOptions
      )) as unknown as VercelSandboxHandle;
    }
  }

  const tokenCredentials = getSkillsAgentSandboxTokenCredentials(env);

  try {
    return (await Sandbox.get({
      name: sessionId,
      projectId: tokenCredentials.projectId,
      teamId: tokenCredentials.teamId,
      token: tokenCredentials.token,
    })) as unknown as VercelSandboxHandle;
  } catch {
    return (await Sandbox.create({
      ...baseOptions,
      projectId: tokenCredentials.projectId,
      teamId: tokenCredentials.teamId,
      token: tokenCredentials.token,
    })) as unknown as VercelSandboxHandle;
  }
}

async function pathExists(localPath: string) {
  try {
    await stat(localPath);
    return true;
  } catch (error) {
    if (
      typeof error === "object" &&
      error !== null &&
      "code" in error &&
      error.code === "ENOENT"
    ) {
      return false;
    }

    throw error;
  }
}

export async function copyLocalPathToSandbox(
  sandbox: VercelSandboxHandle,
  localPath: string,
  remotePath: string
) {
  const entry = await stat(localPath);

  if (entry.isDirectory()) {
    await sandbox.fs.mkdir(remotePath, { recursive: true });

    for (const child of await readdir(localPath)) {
      await copyLocalPathToSandbox(
        sandbox,
        path.join(localPath, child),
        posixPath.join(remotePath, child)
      );
    }

    return;
  }

  await sandbox.fs.mkdir(posixPath.dirname(remotePath), { recursive: true });
  await sandbox.fs.writeFile(remotePath, await readFile(localPath));
}

function resolveSandboxPath(targetPath: string) {
  if (targetPath.startsWith("/")) {
    return targetPath;
  }

  return posixPath.join(VERCEL_SANDBOX_PROJECT_ROOT, targetPath);
}

function shellQuote(value: string) {
  return `'${value.replace(/'/g, `'"'"'`)}'`;
}

function formatSandboxError(error: unknown) {
  if (!(error instanceof Error)) {
    return String(error);
  }

  const details = [
    "response" in error &&
    typeof error.response === "object" &&
    error.response &&
    "status" in error.response &&
    typeof error.response.status === "number"
      ? `HTTP ${error.response.status}`
      : null,
    "sandboxName" in error && typeof error.sandboxName === "string"
      ? `sandbox=${error.sandboxName}`
      : null,
    "sessionId" in error && typeof error.sessionId === "string"
      ? `session=${error.sessionId}`
      : null,
    "json" in error && typeof error.json === "object" && error.json
      ? `json=${JSON.stringify(error.json)}`
      : null,
    "text" in error && typeof error.text === "string" && error.text
      ? `text=${error.text}`
      : null,
    error.message ? `message=${error.message}` : null,
  ].filter(Boolean);

  return details.join(" | ") || error.message;
}

function createSandboxOperationError({
  action,
  error,
  target,
}: {
  action: string;
  error: unknown;
  target: string;
}) {
  return new Error(
    `Sandbox ${action} failed for ${target}. ${formatSandboxError(error)}`
  );
}

async function writeSandboxFile(
  sandbox: VercelSandboxHandle,
  resolvedPath: string,
  content: string
) {
  try {
    await sandbox.fs.mkdir(posixPath.dirname(resolvedPath), {
      recursive: true,
    });
    await sandbox.fs.writeFile(resolvedPath, content, "utf-8");
    return;
  } catch (primaryError) {
    const base64Content = Buffer.from(content, "utf-8").toString("base64");
    const fallbackCommand = [
      `mkdir -p ${shellQuote(posixPath.dirname(resolvedPath))}`,
      `base64 -d > ${shellQuote(resolvedPath)} <<'__SKILLS_AGENT_CONTENT__'`,
      base64Content,
      "__SKILLS_AGENT_CONTENT__",
    ].join("\n");

    let fallbackResult: Awaited<ReturnType<VercelSandboxHandle["runCommand"]>>;

    try {
      fallbackResult = await sandbox.runCommand({
        args: ["-lc", fallbackCommand],
        cmd: "bash",
        cwd: VERCEL_SANDBOX_PROJECT_ROOT,
      });
    } catch (fallbackError) {
      throw new Error(
        [
          `Sandbox writeFile failed for ${resolvedPath}.`,
          `File API error: ${formatSandboxError(primaryError)}`,
          `Shell fallback error: ${formatSandboxError(fallbackError)}`,
        ].join(" ")
      );
    }

    if (fallbackResult.exitCode === 0) {
      return;
    }

    throw new Error(
      [
        "Failed to write a sandbox file.",
        `File API error: ${formatSandboxError(primaryError)}`,
        `Shell fallback error: ${(await fallbackResult.stderr()).trim() || "unknown error"}`,
      ].join(" ")
    );
  }
}

export function createVercelSandboxSessionRegistry({
  createSandbox,
  workspaceRoot = VERCEL_SANDBOX_WORKSPACE_ROOT,
}: {
  createSandbox: VercelSandboxFactory;
  workspaceRoot?: string;
}): VercelSandboxSessionRegistry {
  const entries = new Map<string, SessionEntry>();

  const stopSession = async (sessionId: string) => {
    const entry = entries.get(sessionId);

    if (!entry) {
      return;
    }

    if (!entry.sandboxPromise) {
      entries.delete(sessionId);
      return;
    }

    let sandbox: VercelSandboxHandle;

    try {
      sandbox = await entry.sandboxPromise;
    } catch {
      entries.delete(sessionId);
      return;
    }

    await sandbox.stop();
    entries.delete(sessionId);
  };

  const getOrCreateEntry = (sessionId: string) => {
    const existingEntry = entries.get(sessionId);

    if (existingEntry) {
      return existingEntry;
    }

    const createdEntry: SessionEntry = {
      sandboxPromise: null,
      seededBaseWorkspace: false,
    };
    entries.set(sessionId, createdEntry);
    return createdEntry;
  };

  const ensureSandbox = async (sessionId: string, entry: SessionEntry) => {
    if (!entry.sandboxPromise) {
      entry.sandboxPromise = (async () => {
        let lastError: unknown;

        for (let attempt = 0; attempt < 2; attempt += 1) {
          try {
            const sandbox = await createSandbox(sessionId);

            if (!entry.seededBaseWorkspace) {
              await sandbox.fs.mkdir(VERCEL_SANDBOX_PROJECT_ROOT, {
                recursive: true,
              });
              await sandbox.fs.mkdir(VERCEL_SANDBOX_SKILLS_ROOT, {
                recursive: true,
              });
              await sandbox.fs.mkdir(VERCEL_SANDBOX_ARTIFACTS_ROOT, {
                recursive: true,
              });

              const agentsPath = path.join(workspaceRoot, "AGENTS.md");

              if (await pathExists(agentsPath)) {
                await copyLocalPathToSandbox(
                  sandbox,
                  agentsPath,
                  VERCEL_SANDBOX_AGENTS_FILE
                );
              }

              entry.seededBaseWorkspace = true;
            }

            return sandbox;
          } catch (error) {
            lastError = error;
            entry.seededBaseWorkspace = false;
          }
        }

        throw lastError;
      })().catch((error) => {
        entry.sandboxPromise = null;
        throw error;
      });
    }

    return await entry.sandboxPromise;
  };

  return {
    getSandbox(sessionId) {
      const entry = getOrCreateEntry(sessionId);
      return ensureSandbox(sessionId, entry);
    },
    getSession(sessionId) {
      const entry = getOrCreateEntry(sessionId);

      return {
        artifactsRoot: VERCEL_SANDBOX_ARTIFACTS_ROOT,
        projectRoot: VERCEL_SANDBOX_PROJECT_ROOT,
        sessionId,
        async pathExists(targetPath) {
          const sandbox = await ensureSandbox(sessionId, entry);
          return sandbox.fs.exists(resolveSandboxPath(targetPath));
        },
        async readFile(targetPath) {
          const sandbox = await ensureSandbox(sessionId, entry);
          const resolvedPath = resolveSandboxPath(targetPath);

          try {
            return await sandbox.fs.readFile(resolvedPath, "utf-8");
          } catch (error) {
            throw createSandboxOperationError({
              action: "readFile",
              error,
              target: resolvedPath,
            });
          }
        },
        async runCommand(command) {
          const sandbox = await ensureSandbox(sessionId, entry);
          let result: Awaited<ReturnType<VercelSandboxHandle["runCommand"]>>;

          try {
            result = await sandbox.runCommand({
              args: ["-lc", command],
              cmd: "bash",
              cwd: VERCEL_SANDBOX_PROJECT_ROOT,
            });
          } catch (error) {
            throw createSandboxOperationError({
              action: "bash",
              error,
              target: command,
            });
          }

          return {
            command,
            exitCode: result.exitCode,
            stderr: await result.stderr(),
            stdout: await result.stdout(),
          };
        },
        async stop() {
          await stopSession(sessionId);
        },
        async writeFile(targetPath, content) {
          const sandbox = await ensureSandbox(sessionId, entry);
          const resolvedPath = resolveSandboxPath(targetPath);

          await writeSandboxFile(sandbox, resolvedPath, content);

          return {
            bytes: Buffer.byteLength(content, "utf-8"),
            path: resolvedPath,
          };
        },
      };
    },
    stopSession,
  };
}

let sharedRegistry: VercelSandboxSessionRegistry | null = null;

export function getSharedVercelSandboxSessionRegistry(
  env: SkillsAgentEnv = getSkillsAgentEnv()
) {
  sharedRegistry ??= createVercelSandboxSessionRegistry({
    createSandbox: (sessionId) => createVercelSandbox(sessionId, env),
  });

  return sharedRegistry;
}

import { readFile } from "node:fs/promises";
import path from "node:path";
import { getSkillsAgentEnv } from "./env";
import { SKILLS_AGENT_WORKSPACE_ROOT } from "./local-skill-catalog";
import {
  createSkillsAgentOfficialTools,
  type SkillsAgentOfficialTools,
} from "./official-tools";
import {
  getSharedSkillsAgentSessionRegistry,
  SANDBOX_ARTIFACTS_ROOT,
  SANDBOX_PROJECT_ROOT,
  type SkillsAgentSession,
} from "./sandbox";
import type { SkillMetadata } from "./skill-catalog";

type DemoEnv = Record<string, string | undefined>;

export interface VisibleSkillMetadata {
  description: string;
  name: string;
  path: string;
}

export interface SkillsAgentWorkspace {
  readonly artifactsRoot: string;
  readonly projectRoot: string;
  readonly session: SkillsAgentSession;
  readonly toolset: SkillsAgentOfficialTools;
  readonly visibleSkillCatalog: VisibleSkillMetadata[];
  readonly visibleSkillCatalogText: string;
}

export const SKILLS_AGENT_AGENTS_PATH = path.join(
  SKILLS_AGENT_WORKSPACE_ROOT,
  "AGENTS.md"
);
export const SKILLS_AGENT_SKILLS_DIRECTORY = path.join(
  SKILLS_AGENT_WORKSPACE_ROOT,
  ".agents/skills"
);

export function toVisibleSkillCatalog(
  skills: SkillMetadata[]
): VisibleSkillMetadata[] {
  return skills.map(({ description, name, path }) => ({
    description,
    name,
    path,
  }));
}

export function formatVisibleSkillCatalog(skills: VisibleSkillMetadata[]) {
  return skills
    .map(
      (skill) => `- ${skill.name}: ${skill.description} (path: ${skill.path})`
    )
    .join("\n");
}

export async function createSkillsAgentWorkspace(
  {
    env = getSkillsAgentEnv(),
    sessionId,
    skills,
  }: {
    env?: DemoEnv;
    sessionId: string;
    skills: SkillMetadata[];
  },
  dependencies: {
    createOfficialTools?: typeof createSkillsAgentOfficialTools;
    readAgentsFile?: typeof readFile;
  } = {}
): Promise<SkillsAgentWorkspace> {
  const readAgentsFile = dependencies.readAgentsFile ?? readFile;
  const createOfficialTools =
    dependencies.createOfficialTools ?? createSkillsAgentOfficialTools;
  const session =
    getSharedSkillsAgentSessionRegistry(env).getSession(sessionId);
  const visibleSkillCatalog = toVisibleSkillCatalog(skills);
  const agentsContent = await readAgentsFile(SKILLS_AGENT_AGENTS_PATH, "utf-8");
  const toolset = await createOfficialTools({
    agentsContent,
    projectRoot: SANDBOX_PROJECT_ROOT,
    session,
    skillsDirectory: SKILLS_AGENT_SKILLS_DIRECTORY,
  });

  return {
    artifactsRoot: SANDBOX_ARTIFACTS_ROOT,
    projectRoot: SANDBOX_PROJECT_ROOT,
    session,
    toolset,
    visibleSkillCatalog,
    visibleSkillCatalogText: formatVisibleSkillCatalog(visibleSkillCatalog),
  };
}

#!/usr/bin/env python3
"""
Quick validation script for skills - minimal version
"""

import re
import sys
from pathlib import Path

import yaml

MAX_SKILL_NAME_LENGTH = 64


def validate_skill(skill_path):
    """Basic validation of a skill"""
    skill_path = Path(skill_path)

    skill_md = skill_path / "SKILL.md"
    if not skill_md.exists():
        return False, "SKILL.md not found"

    content = skill_md.read_text()
    if not content.startswith("---"):
        return False, "No YAML frontmatter found"

    match = re.match(r"^---\n(.*?)\n---", content, re.DOTALL)
    if not match:
        return False, "Invalid frontmatter format"

    frontmatter_text = match.group(1)

    try:
        frontmatter = yaml.safe_load(frontmatter_text)
        if not isinstance(frontmatter, dict):
            return False, "Frontmatter must be a YAML dictionary"
    except yaml.YAMLError as e:
        return False, f"Invalid YAML in frontmatter: {e}"

    allowed_properties = {"name", "description", "license", "allowed-tools", "metadata"}

    unexpected_keys = set(frontmatter.keys()) - allowed_properties
    if unexpected_keys:
        allowed = ", ".join(sorted(allowed_properties))
        unexpected = ", ".join(sorted(unexpected_keys))
        return (
            False,
            f"Unexpected key(s) in SKILL.md frontmatter: {unexpected}. Allowed properties are: {allowed}",
        )

    if "name" not in frontmatter:
        return False, "Missing 'name' in frontmatter"
    if "description" not in frontmatter:
        return False, "Missing 'description' in frontmatter"

    name = frontmatter.get("name", "")
    if not isinstance(name, str):
        return False, f"Name must be a string, got {type(name).__name__}"
    name = name.strip()
    if name:
        if not re.match(r"^[a-z0-9-]+$", name):
            return (
                False,
                f"Name '{name}' should be hyphen-case (lowercase letters, digits, and hyphens only)",
            )
        if name.startswith("-") or name.endswith("-") or "--" in name:
            return (
                False,
                f"Name '{name}' cannot start/end with hyphen or contain consecutive hyphens",
            )
        if len(name) > MAX_SKILL_NAME_LENGTH:
            return (
                False,
                f"Name is too long ({len(name)} characters). "
                f"Maximum is {MAX_SKILL_NAME_LENGTH} characters.",
            )

    description = frontmatter.get("description", "")
    if not isinstance(description, str):
        return False, f"Description must be a string, got {type(description).__name__}"
    description = description.strip()
    if description:
        if "<" in description or ">" in description:
            return False, "Description cannot contain angle brackets (< or >)"
        if len(description) > 1024:
            return (
                False,
                f"Description is too long ({len(description)} characters). Maximum is 1024 characters.",
            )

    return True, "Skill is valid!"


if __name__ == "__main__":
    if len(sys.argv) != 2:
        print("Usage: python quick_validate.py <skill_directory>")
        sys.exit(1)

    valid, message = validate_skill(sys.argv[1])
    print(message)
    sys.exit(0 if valid else 1)
